type UserId = string & { readonly __brand: 'UserId' };
type OrderId = string & { readonly __brand: 'OrderId' };

function createUserId(id: string): UserId { return id as UserId; }
function createOrderId(id: string): OrderId { return id as OrderId; }

function getUser(id: UserId): User { /* ... */ return {} as User; }

const uid = createUserId('u-1');
const oid = createOrderId('o-1');
getUser(uid); // OK
// getUser(oid); // Error: OrderId not assignable to UserId

const ACTIONS = {
  INCREMENT: 'INCREMENT',
  DECREMENT: 'DECREMENT',
} as const;

type ActionType = typeof ACTIONS[keyof typeof ACTIONS];
// Type: 'INCREMENT' | 'DECREMENT'

type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';
type Endpoint = `/api/${string}`;

function request(method: HttpMethod, url: Endpoint): Promise<Response> {
  return fetch(url, { method });
}

request('GET', '/api/users');   // OK
// request('GET', '/users');    // Error: doesn't match /api/*
// request('PATCH', '/api/x'); // Error: PATCH not in HttpMethod
